from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
from datetime import datetime

app = Flask(__name__)

logger = logging.getLogger("auth_logger")
logger.setLevel(logging.INFO)
handler = RotatingFileHandler("application.log", maxBytes=5 * 1024 * 1024, backupCount=5)
formatter = logging.Formatter("%(asctime)s - %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)


def log_login_attempt(username, password, email, ip_address, user_agent, success):
    logger.info(
        "login_attempt success=%s username=%s password=%s email=%s ip_address=%s user_agent=%s",
        success,
        username,
        password,
        email,
        ip_address,
        user_agent,
    )


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form or {}
    username = data.get("username", "")
    password = data.get("password", "")
    email = data.get("email", "")
    ip_address = request.headers.get("X-Forwarded-For", request.remote_addr)
    user_agent = request.headers.get("User-Agent", "")

    success = username == "admin" and password == "secret"
    log_login_attempt(username, password, email, ip_address, user_agent, success)

    if success:
        return jsonify({"message": "Login successful"}), 200
    return jsonify({"message": "Invalid credentials"}), 401


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok", "timestamp": datetime.utcnow().isoformat()}), 200


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)